        report errorMessage(EntityName_c, "Fractional mode is only supported for FreqClkHz_g < 1'000'000 x FreqStrobeHz_g")
        severity failure;

    -- Ratio between FreqClkHz_g and FreqStrobeHz_g must be <= 2'147'483'000

